43	func ParseMapping(raw string) (RefMapping, error) {
44		parts := strings.SplitN(raw, ":", 2)
45		if len(parts) != 2 {
46			return RefMapping{}, fmt.Errorf("invalid --map %q, expected src:dst", raw)
47		}
48		source := strings.TrimSpace(parts[0])
49		target := strings.TrimSpace(parts[1])
50		if source == "" || target == "" {
51			return RefMapping{}, fmt.Errorf("invalid --map %q, expected src:dst", raw)
52		}
53		return RefMapping{Source: source, Target: target}, nil
54	}
