57	// branch names for compatibility with other CLI ref selectors.
58	func ParseHaveRef(raw string) plumbing.ReferenceName {
59		raw = strings.TrimSpace(raw)
60		if strings.HasPrefix(raw, "refs/") {
61			return plumbing.ReferenceName(raw)
62		}
63		return plumbing.NewBranchReferenceName(raw)
64	}
65	
66	// NormalizeMapping validates and normalizes a single ref mapping.
67	func NormalizeMapping(m RefMapping) (NormalizedMapping, error) {
68		src := strings.TrimSpace(m.Source)
69		dst := strings.TrimSpace(m.Target)
70		if src == "" || dst == "" {
71			return NormalizedMapping{}, fmt.Errorf("invalid mapping %q:%q: source and target must be non-empty", m.Source, m.Target)
72		}
73	
74		srcFQ := strings.HasPrefix(src, "refs/")
75		dstFQ := strings.HasPrefix(dst, "refs/")
76	
77		if srcFQ && dstFQ {
78			sourceRef := plumbing.ReferenceName(src)
