84			}
85			if dstKind == "" {
86				return NormalizedMapping{}, fmt.Errorf("unsupported target ref kind: %s", dst)
87			}
88			if srcKind != dstKind {
89				return NormalizedMapping{}, fmt.Errorf("cross-kind mapping not allowed: %s (%s) -> %s (%s)", src, srcKind, dst, dstKind)
90			}
