250		fs.StringVar(&sourceAuth.Token, "source-token", envOr("GITSYNC_SOURCE_TOKEN", ""), "source token/password")
251		fs.StringVar(&targetAuth.Token, "target-token", envOr("GITSYNC_TARGET_TOKEN", ""), "target token/password")
252		fs.StringVar(&sourceAuth.Username, "source-username", envOr("GITSYNC_SOURCE_USERNAME", "git"), "source basic auth username")
253		fs.StringVar(&targetAuth.Username, "target-username", envOr("GITSYNC_TARGET_USERNAME", "git"), "target basic auth username")
254		fs.StringVar(&sourceAuth.BearerToken, "source-bearer-token", envOr("GITSYNC_SOURCE_BEARER_TOKEN", ""), "source bearer token")
255		fs.StringVar(&targetAuth.BearerToken, "target-bearer-token", envOr("GITSYNC_TARGET_BEARER_TOKEN", ""), "target bearer token")
256		fs.BoolVar(&sourceAuth.SkipTLSVerify, "source-insecure-skip-tls-verify", envBool("GITSYNC_SOURCE_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the source")
257		fs.BoolVar(&targetAuth.SkipTLSVerify, "target-insecure-skip-tls-verify", envBool("GITSYNC_TARGET_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the target")
258		fs.BoolVar(&req.IncludeTags, "tags", false, "include tag ref prefixes in probe")
259		probeProtocol := protocolModeFlag(protocolMode(envOr("GITSYNC_PROTOCOL", validation.ProtocolAuto)))
260		fs.Var(&probeProtocol, "protocol", "protocol mode: auto, v1, or v2")
261		fs.BoolVar(&req.Options.CollectStats, "stats", false, "print transfer statistics")
262		fs.BoolVar(&req.Options.MeasureMemory, "measure-memory", false, "sample elapsed time and Go heap usage")
263		fs.BoolVar(&jsonOutput, "json", false, "print JSON output")
264	
265		if err := fs.Parse(args); err != nil {
266			return fmt.Errorf("parse flags: %w", err)
267		}
268		req.Protocol = gitsync.ProtocolMode(probeProtocol)
269	
270		positional := fs.Args()
271		if req.Source.URL == "" && len(positional) > 0 {
272			req.Source.URL = positional[0]
273		}
274		if *targetURL == "" && len(positional) > 1 {
275			*targetURL = positional[1]
276		}
277		if len(positional) > 2 {
278			return usageError("too many positional arguments")
279		}
280		if req.Source.URL == "" {
281			return usageError("probe requires a source repository URL")
282		}
283		if *targetURL != "" {
284			req.Target = &gitsync.Endpoint{
285				URL:                    *targetURL,
286				FollowInfoRefsRedirect: targetFollowInfoRefsRedirect,
287			}
288		}
289	
290		result, err := unstable.New(unstable.Options{
291			Auth: gitsync.StaticAuthProvider{Source: sourceAuth, Target: targetAuth},
292		}).Probe(ctx, req)
293		if err != nil {
294			return fmt.Errorf("probe: %w", err)
295		}
296		printOutput(jsonOutput, result)
297		return nil
298	}
299	
300	func runFetch(ctx context.Context, args []string) error {
301		fs := flag.NewFlagSet("fetch", flag.ContinueOnError)
302		fs.SetOutput(os.Stderr)
303	
304		var haveRefs multiStringFlag
305		var haveHashesRaw multiStringFlag
306		var jsonOutput bool
307		var sourceAuth gitsync.EndpointAuth
308		req := unstable.FetchRequest{}
309	
310		fs.StringVar(&req.Source.URL, "source-url", "", "source repository URL")
311		fs.BoolVar(&req.Source.FollowInfoRefsRedirect, "source-follow-info-refs-redirect", envBool("GITSYNC_SOURCE_FOLLOW_INFO_REFS_REDIRECT"), "send follow-up source RPCs to the final /info/refs redirect host")
312		fs.StringVar(&sourceAuth.Token, "source-token", envOr("GITSYNC_SOURCE_TOKEN", ""), "source token/password")
313		fs.StringVar(&sourceAuth.Username, "source-username", envOr("GITSYNC_SOURCE_USERNAME", "git"), "source basic auth username")
314		fs.StringVar(&sourceAuth.BearerToken, "source-bearer-token", envOr("GITSYNC_SOURCE_BEARER_TOKEN", ""), "source bearer token")
315		fs.BoolVar(&sourceAuth.SkipTLSVerify, "source-insecure-skip-tls-verify", envBool("GITSYNC_SOURCE_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the source")
316		branches := fs.String("branch", "", "comma-separated branch list; default is all source branches")
317		fs.BoolVar(&req.IncludeTags, "tags", false, "include tags in the fetch request")
318		fetchProtocol := protocolModeFlag(protocolMode(envOr("GITSYNC_PROTOCOL", validation.ProtocolAuto)))
319		fs.Var(&fetchProtocol, "protocol", "protocol mode: auto, v1, or v2")
320		fs.BoolVar(&req.Options.CollectStats, "stats", false, "print transfer statistics")
321		fs.BoolVar(&req.Options.MeasureMemory, "measure-memory", false, "sample elapsed time and Go heap usage")
322		fs.BoolVar(&jsonOutput, "json", false, "print JSON output")
323		fs.Var(&haveRefs, "have-ref", "source ref name to advertise as have; short names map to branches")
324		fs.Var(&haveHashesRaw, "have", "explicit object hash to advertise as have")
325	
326		if err := fs.Parse(args); err != nil {
327			return fmt.Errorf("parse flags: %w", err)
328		}
329		req.Protocol = gitsync.ProtocolMode(fetchProtocol)
330	
331		positional := fs.Args()
332		if req.Source.URL == "" && len(positional) > 0 {
333			req.Source.URL = positional[0]
334		}
335		if len(positional) > 1 {
336			return usageError("too many positional arguments")
337		}
338		if req.Source.URL == "" {
339			return usageError("fetch requires a source repository URL")
340		}
341		if *branches != "" {
342			req.Scope.Branches = splitCSV(*branches)
343		}
344	
345		haveHashes := make([]plumbing.Hash, 0, len(haveHashesRaw))
346		for _, raw := range haveHashesRaw {
347			hash := plumbing.NewHash(strings.TrimSpace(raw))
348			if hash.IsZero() {
349				return fmt.Errorf("invalid --have %q", raw)
350			}
351			haveHashes = append(haveHashes, hash)
352		}
353	
354		req.HaveRefs = append(req.HaveRefs, haveRefs...)
355		req.HaveHashes = append(req.HaveHashes, haveHashes...)
356		result, err := unstable.New(unstable.Options{
357			Auth: gitsync.StaticAuthProvider{Source: sourceAuth},
358		}).Fetch(ctx, req)
359		if err != nil {
360			return fmt.Errorf("fetch: %w", err)
361		}
362		printOutput(jsonOutput, result)
363		return nil
364	}
