366	func printOutput(jsonOutput bool, value interface{ Lines() []string }) {
367		if jsonOutput {
368			data, err := marshalOutput(value)
369			if err != nil {
370				fmt.Fprintf(os.Stderr, "error: encode JSON output: %v\n", err)
371				os.Exit(1)
372			}
373			fmt.Println(string(data))
374			return
375		}
376	
377		for _, line := range value.Lines() {
378			fmt.Println(line)
379		}
380	}
381	
382	func marshalOutput(value interface{}) ([]byte, error) {
383		data, err := json.MarshalIndent(value, "", "  ")
384		if err != nil {
385			return nil, fmt.Errorf("marshal JSON: %w", err)
386		}
387		return data, nil
388	}
