401	func splitCSV(value string) []string {
402		parts := strings.Split(value, ",")
403		out := make([]string, 0, len(parts))
404		for _, part := range parts {
405			part = strings.TrimSpace(part)
406			if part != "" {
407				out = append(out, part)
408			}
409		}
410		return out
411	}
