571	type protocolModeFlag protocolMode
572	type operationModeFlag operationMode
573	
574	func (p *protocolModeFlag) String() string {
575		return string(*p)
576	}
577	
578	func (p *protocolModeFlag) Set(value string) error {
579		mode, err := validation.NormalizeProtocolMode(value)
580		if err != nil {
581			return fmt.Errorf("normalize protocol: %w", err)
582		}
583		*p = protocolModeFlag(protocolMode(gitsync.ProtocolMode(mode)))
584		return nil
585	}
586	
587	func (m *operationModeFlag) String() string {
588		return string(*m)
589	}
590	
591	func (m *operationModeFlag) Set(value string) error {
592		switch gitsync.OperationMode(value) {
593		case gitsync.ModeSync, gitsync.ModeReplicate:
594			*m = operationModeFlag(operationMode(value))
595			return nil
596		default:
597			return fmt.Errorf("unsupported mode %q", value)
598		}
599	}
600	
601	// defaultOperationMode returns the starting value for the --mode flag.
602	// Subcommands that pin a mode (sync, replicate) pass it in; plan passes ""
603	// and gets sync as the default, letting --mode override it.
604	func defaultOperationMode(defaultMode gitsync.OperationMode) operationMode {
605		if defaultMode != "" {
606			return operationMode(defaultMode)
607		}
608		return operationMode(gitsync.ModeSync)
609	}
