35				return fmt.Errorf("source ref %s not found", sourceRef)
36			}
37			// Reject duplicate target refs from different sources (issue #2, #3).
38			if existing, ok := desired[targetRef]; ok && existing.SourceRef != sourceRef {
39				return fmt.Errorf("duplicate target ref %s: mapped from both %s and %s", targetRef, existing.SourceRef, sourceRef)
40			}
41			short := targetRef.Short()
42			desired[targetRef] = DesiredRef{
43				Kind:       kind,
44				Label:      short,
45				SourceRef:  sourceRef,
46				TargetRef:  targetRef,
47				SourceHash: hash,
48			}
49			managed[targetRef] = ManagedTarget{Kind: kind, Label: short}
50			return nil
51		}
52	
53		if len(cfg.Mappings) > 0 {
54			// Validate all mappings up front (issue #2, #3)
55			normalized, err := validation.ValidateMappings(cfg.Mappings)
56			if err != nil {
57				return nil, nil, fmt.Errorf("validate ref mappings: %w", err)
58			}
59			for _, nm := range normalized {
60				kind := RefKindFromName(nm.TargetRef)
61				if err := addManaged(nm.SourceRef, nm.TargetRef, kind, sourceRefs[nm.SourceRef]); err != nil {
62					return nil, nil, err
63				}
64			}
65		} else {
66			branches := BranchMapFromRefHashMap(sourceRefs)
67			selected := SelectBranches(branches, cfg.Branches)
68			for branch, hash := range selected {
69				refName := plumbing.NewBranchReferenceName(branch)
70				if err := addManaged(refName, refName, RefKindBranch, hash); err != nil {
71					return nil, nil, err
72				}
73			}
74		}
75	
76		if cfg.IncludeTags {
77			for refName, hash := range sourceRefs {
78				if !refName.IsTag() {
79					continue
80				}
81				if err := addManaged(refName, refName, RefKindTag, hash); err != nil {
82					return nil, nil, err
83				}
84			}
85		}
86	
87		return desired, managed, nil
88	}
89	
90	// BuildPlans generates the action plans for each managed ref.
91	func BuildPlans(
92		store storer.EncodedObjectStorer,
93		desired map[plumbing.ReferenceName]DesiredRef,
94		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
95		managed map[plumbing.ReferenceName]ManagedTarget,
96		cfg PlanConfig,
97	) ([]BranchPlan, error) {
98		if cfg.Prune {
99			for targetRef := range targetRefs {
100				if _, ok := managed[targetRef]; ok {
101					continue
102				}
103				switch {
104				case targetRef.IsTag() && cfg.IncludeTags:
105					managed[targetRef] = ManagedTarget{Kind: RefKindTag, Label: targetRef.Short()}
106				case targetRef.IsBranch() && len(cfg.Mappings) == 0 && len(cfg.Branches) == 0:
107					managed[targetRef] = ManagedTarget{Kind: RefKindBranch, Label: targetRef.Short()}
108				}
109			}
110		}
111	
112		targetNames := make([]plumbing.ReferenceName, 0, len(managed))
113		for name := range managed {
114			targetNames = append(targetNames, name)
115		}
116		sort.Slice(targetNames, func(i, j int) bool { return targetNames[i] < targetNames[j] })
117	
118		plans := make([]BranchPlan, 0, len(targetNames))
119		for _, targetRef := range targetNames {
120			info := managed[targetRef]
121			want, existsInDesired := desired[targetRef]
122			targetHash, existsOnTarget := targetRefs[targetRef]
123	
124			if !existsInDesired {
125				if cfg.Prune && existsOnTarget {
126					plans = append(plans, BranchPlan{
127						Branch:     info.Label,
128						TargetRef:  targetRef,
129						TargetHash: targetHash,
130						Kind:       info.Kind,
131						Action:     ActionDelete,
132						Reason:     ShortHash(targetHash) + " -> <deleted>",
133					})
134				}
135				continue
136			}
137	
138			if !existsOnTarget {
139				plans = append(plans, BranchPlan{
140					Branch:     want.Label,
141					SourceRef:  want.SourceRef,
142					TargetRef:  want.TargetRef,
143					SourceHash: want.SourceHash,
144					Kind:       want.Kind,
145					Action:     ActionCreate,
146					Reason:     ShortHash(want.SourceHash) + " -> <new>",
147				})
148				continue
149			}
150	
151			plan, err := PlanRef(store, want, targetHash, cfg.Force)
152			if err != nil {
153				return nil, err
154			}
155			plans = append(plans, plan)
156		}
157	
158		sort.Slice(plans, func(i, j int) bool {
159			return plans[i].TargetRef.String() < plans[j].TargetRef.String()
160		})
161		return plans, nil
162	}
163	
164	// BuildReplicationPlans generates overwrite-oriented plans for replication mode.
165	// Divergent refs are updated directly rather than blocked.
166	//
167	//nolint:unparam // error return kept for API consistency with BuildPlans
168	func BuildReplicationPlans(
169		desired map[plumbing.ReferenceName]DesiredRef,
170		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
171		managed map[plumbing.ReferenceName]ManagedTarget,
172		cfg PlanConfig,
173	) ([]BranchPlan, error) {
174		managed = copyManagedTargets(managed)
175		if cfg.Prune {
176			for targetRef := range targetRefs {
177				if _, ok := managed[targetRef]; ok {
178					continue
179				}
180				switch {
181				case targetRef.IsTag() && cfg.IncludeTags:
182					managed[targetRef] = ManagedTarget{Kind: RefKindTag, Label: targetRef.Short()}
183				case targetRef.IsBranch() && len(cfg.Mappings) == 0 && len(cfg.Branches) == 0:
184					managed[targetRef] = ManagedTarget{Kind: RefKindBranch, Label: targetRef.Short()}
185				}
186			}
187		}
188	
189		targetNames := make([]plumbing.ReferenceName, 0, len(managed))
190		for name := range managed {
191			targetNames = append(targetNames, name)
192		}
193		sort.Slice(targetNames, func(i, j int) bool { return targetNames[i] < targetNames[j] })
194	
195		plans := make([]BranchPlan, 0, len(targetNames))
196		for _, targetRef := range targetNames {
197			info := managed[targetRef]
198			want, existsInDesired := desired[targetRef]
199			targetHash, existsOnTarget := targetRefs[targetRef]
200	
201			if !existsInDesired {
202				if cfg.Prune && existsOnTarget {
203					plans = append(plans, BranchPlan{
204						Branch:     info.Label,
205						TargetRef:  targetRef,
206						TargetHash: targetHash,
207						Kind:       info.Kind,
208						Action:     ActionDelete,
209						Reason:     ShortHash(targetHash) + " -> <deleted>",
210					})
211				}
212				continue
213			}
214	
215			plans = append(plans, PlanReplicationRef(want, targetHash, existsOnTarget))
216		}
217	
218		sort.Slice(plans, func(i, j int) bool {
219			return plans[i].TargetRef.String() < plans[j].TargetRef.String()
220		})
221		return plans, nil
222	}
223	
224	func copyManagedTargets(input map[plumbing.ReferenceName]ManagedTarget) map[plumbing.ReferenceName]ManagedTarget {
225		out := make(map[plumbing.ReferenceName]ManagedTarget, len(input))
226		for k, v := range input {
227			out[k] = v
228		}
229		return out
230	}
231	
232	// BuildBootstrapPlans creates plans for an empty-target bootstrap.
233	func BuildBootstrapPlans(
234		desired map[plumbing.ReferenceName]DesiredRef,
235		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
236	) ([]BranchPlan, error) {
237		targetNames := make([]plumbing.ReferenceName, 0, len(desired))
238		for _, want := range desired {
239			targetNames = append(targetNames, want.TargetRef)
240		}
241		sort.Slice(targetNames, func(i, j int) bool { return targetNames[i] < targetNames[j] })
242	
243		plans := make([]BranchPlan, 0, len(targetNames))
244		for _, targetRef := range targetNames {
245			targetHash := targetRefs[targetRef]
246			if !targetHash.IsZero() {
247				return nil, fmt.Errorf("target ref %s already exists; use sync for non-bootstrap runs", targetRef)
248			}
249			want := desired[targetRef]
250			plans = append(plans, BranchPlan{
251				Branch:     want.Label,
252				SourceRef:  want.SourceRef,
253				TargetRef:  want.TargetRef,
254				SourceHash: want.SourceHash,
255				TargetHash: plumbing.ZeroHash,
256				Kind:       want.Kind,
257				Action:     ActionCreate,
258				Reason:     fmt.Sprintf("create %s at %s", want.TargetRef, ShortHash(want.SourceHash)),
259			})
260		}
261		return plans, nil
262	}
263	
264	// PlanRef determines the action for a single ref that exists on both source and target.
265	func PlanRef(store storer.EncodedObjectStorer, want DesiredRef, targetHash plumbing.Hash, force bool) (BranchPlan, error) {
266		plan := BranchPlan{
267			Branch:     want.Label,
268			SourceRef:  want.SourceRef,
269			TargetRef:  want.TargetRef,
270			SourceHash: want.SourceHash,
271			TargetHash: targetHash,
272			Kind:       want.Kind,
273		}
274	
275		if want.SourceHash == targetHash {
276			plan.Action = ActionSkip
277			plan.Reason = ShortHash(want.SourceHash) + " already current"
278			return plan, nil
279		}
280	
281		if want.Kind == RefKindTag {
282			if force {
283				plan.Action = ActionUpdate
284				plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (force tag update)"
285				return plan, nil
286			}
287			plan.Action = ActionBlock
288			plan.Reason = ShortHash(targetHash) + " differs from " + ShortHash(want.SourceHash) + "; use --force to retarget tag"
289			return plan, nil
290		}
291	
292		isFF, err := ReachesCommit(store, want.SourceHash, targetHash)
293		if err != nil {
294			if errors.Is(err, ErrAncestryDepthExceeded) {
295				// Can't prove fast-forward within depth limit — block with explanation.
296				plan.Action = ActionBlock
297				plan.Reason = "ancestry check for " + want.TargetRef.String() + " exceeded depth limit; use --force if this is a valid fast-forward"
298				return plan, nil
299			}
300			return plan, fmt.Errorf("check fast-forward for %s: %w", want.TargetRef, err)
301		}
302		if isFF {
303			plan.Action = ActionUpdate
304			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash)
305			return plan, nil
306		}
307	
308		if force {
309			plan.Action = ActionUpdate
310			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (force)"
311			return plan, nil
312		}
313	
314		plan.Action = ActionBlock
315		plan.Reason = ShortHash(targetHash) + " is not an ancestor of " + ShortHash(want.SourceHash)
316		return plan, nil
317	}
318	
319	// PlanReplicationRef determines the overwrite-oriented action for a single ref.
320	func PlanReplicationRef(want DesiredRef, targetHash plumbing.Hash, existsOnTarget bool) BranchPlan {
321		plan := BranchPlan{
322			Branch:     want.Label,
323			SourceRef:  want.SourceRef,
324			TargetRef:  want.TargetRef,
325			SourceHash: want.SourceHash,
326			TargetHash: targetHash,
327			Kind:       want.Kind,
328		}
329	
330		if want.SourceHash == targetHash {
331			plan.Action = ActionSkip
332			plan.Reason = ShortHash(want.SourceHash) + " already current"
333			return plan
334		}
335	
336		if !existsOnTarget || targetHash.IsZero() {
337			plan.Action = ActionCreate
338			plan.Reason = ShortHash(want.SourceHash) + " -> <new>"
339			return plan
340		}
341	
342		plan.Action = ActionUpdate
343		switch want.Kind {
344		case RefKindTag:
345			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (replicate tag overwrite)"
346		case RefKindBranch:
347			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (replicate overwrite)"
348		default:
349			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (replicate overwrite)"
350		}
351		return plan
352	}
353	
354	// MaxAncestryDepth is the maximum number of commits to visit during a
355	// fast-forward ancestry check. This prevents full graph walks on very
356	// large histories (issue #16). Set high enough to avoid false negatives
357	// on real repos — even the Linux kernel has ~1.3M commits.
358	const MaxAncestryDepth = 2_000_000
359	
360	// ErrAncestryDepthExceeded is returned when ReachesCommit exceeds MaxAncestryDepth.
361	var ErrAncestryDepthExceeded = errors.New("ancestry check exceeded depth limit")
362	
363	// ReachesCommit checks whether the commit at startHash has targetHash as an
364	// ancestor, bounded to MaxAncestryDepth commits to prevent degenerate walks.
365	func ReachesCommit(store storer.EncodedObjectStorer, startHash, targetHash plumbing.Hash) (bool, error) {
366		if startHash == targetHash {
367			return true, nil
368		}
369	
370		start, err := object.GetCommit(store, startHash)
371		if err != nil {
372			return false, fmt.Errorf("load source commit %s: %w", startHash, err)
373		}
374	
375		seen := map[plumbing.Hash]struct{}{}
376		stack := []*object.Commit{start}
377	
378		for len(stack) > 0 {
379			if len(seen) >= MaxAncestryDepth {
380				return false, ErrAncestryDepthExceeded
381			}
382			current := stack[len(stack)-1]
383			stack = stack[:len(stack)-1]
384			if _, ok := seen[current.Hash]; ok {
385				continue
386			}
387			seen[current.Hash] = struct{}{}
388	
389			for _, parentHash := range current.ParentHashes {
390				if parentHash == targetHash {
391					return true, nil
392				}
393				if _, ok := seen[parentHash]; ok {
394					continue
395				}
396				parent, err := object.GetCommit(store, parentHash)
397				if err != nil {
398					if errors.Is(err, plumbing.ErrObjectNotFound) {
399						continue
400					}
401					return false, fmt.Errorf("load parent commit %s: %w", parentHash, err)
402				}
403				stack = append(stack, parent)
404			}
405		}
406		return false, nil
407	}
408	
409	// ObjectsToPush computes the set of objects that need to be sent to the target.
410	func ObjectsToPush(store storer.EncodedObjectStorer, wants []plumbing.Hash, targetRefs map[plumbing.ReferenceName]plumbing.Hash) ([]plumbing.Hash, error) {
411		haveSet := make(map[plumbing.Hash]struct{})
412		for _, h := range targetRefs {
413			if !h.IsZero() {
414				haveSet[h] = struct{}{}
415			}
416		}
417	
418		filteredWants := make([]plumbing.Hash, 0, len(wants))
419		for _, h := range wants {
420			if _, ok := haveSet[h]; !ok {
421				filteredWants = append(filteredWants, h)
422			}
423		}
424		if len(filteredWants) == 0 {
425			return nil, nil
426		}
427	
428		seen := make(map[plumbing.Hash]bool, len(filteredWants)*4)
429		objects := make([]plumbing.Hash, 0, len(filteredWants)*16)
430		for _, h := range filteredWants {
431			if err := collectObjects(store, h, haveSet, seen, &objects); err != nil {
432				return nil, err
433			}
434		}
435		return objects, nil
436	}
437	
438	func collectObjects(
439		store storer.EncodedObjectStorer,
440		hash plumbing.Hash,
441		haves map[plumbing.Hash]struct{},
442		seen map[plumbing.Hash]bool,
443		out *[]plumbing.Hash,
444	) error {
445		if hash.IsZero() {
446			return nil
447		}
448		if _, ok := haves[hash]; ok {
449			return nil
450		}
451		if seen[hash] {
452			return nil
453		}
454		seen[hash] = true
455	
456		obj, err := store.EncodedObject(plumbing.AnyObject, hash)
457		if err != nil {
458			return fmt.Errorf("load object %s: %w", hash, err)
459		}
460	
461		switch obj.Type() {
462		case plumbing.CommitObject:
463			commit, err := object.GetCommit(store, hash)
464			if err != nil {
465				return fmt.Errorf("load commit %s: %w", hash, err)
466			}
467			if err := collectObjects(store, commit.TreeHash, haves, seen, out); err != nil {
468				return err
469			}
470			for _, ph := range commit.ParentHashes {
471				if err := collectObjects(store, ph, haves, seen, out); err != nil {
472					return err
473				}
474			}
475		case plumbing.TreeObject:
476			tree, err := object.GetTree(store, hash)
477			if err != nil {
478				return fmt.Errorf("load tree %s: %w", hash, err)
479			}
480			for _, entry := range tree.Entries {
481				if err := collectObjects(store, entry.Hash, haves, seen, out); err != nil {
482					return err
483				}
484			}
485		case plumbing.TagObject:
486			tag, err := object.GetTag(store, hash)
487			if err != nil {
488				return fmt.Errorf("load tag %s: %w", hash, err)
489			}
490			if err := collectObjects(store, tag.Target, haves, seen, out); err != nil {
491				return err
492			}
493		case plumbing.BlobObject:
494			// Blobs are leaf objects — nothing to recurse into.
495		case plumbing.InvalidObject, plumbing.OFSDeltaObject, plumbing.REFDeltaObject, plumbing.AnyObject:
496			return fmt.Errorf("unsupported object type %s for %s", obj.Type(), hash)
497		}
498	
499		*out = append(*out, hash)
500		return nil
501	}
