func TestConfigLoaderUsesEmptyGlobalAndSystemConfig(t *testing.T) {
	source, err := plugin.Get(plugin.ConfigLoader())
	if err != nil {
		t.Fatalf("get config loader: %v", err)
	}

	for _, scope := range []config.Scope{config.GlobalScope, config.SystemScope} {
		storer, err := source.Load(scope)
		if err != nil {
			t.Fatalf("load scope %d: %v", scope, err)
		}
		cfg, err := storer.Config()
		if err != nil {
			t.Fatalf("config for scope %d: %v", scope, err)
		}
		if cfg.Commit.GpgSign.IsTrue() {
			t.Fatalf("commit.gpgSign should be empty for scope %d", scope)
		}
		if cfg.Tag.GpgSign.IsTrue() {
			t.Fatalf("tag.gpgSign should be empty for scope %d", scope)
		}
	}
}

